impl Solution { pub fn length_after_transformations(s: String, t: i32) -> i32 { let (mut black_counts, black_mod) = (vec![0i64; 26], 1_000_000_007i64); for b in s.bytes() { black_counts[(b - b'a') as usize] += 1; } for _ in 0..t { let mut black_next = vec![0i64; 26]; for i in 0..26 { if i == 25 { black_next[0] = (black_next[0] + black_counts[25]) % black_mod; black_next[1] = (black_next[1] + black_counts[25]) % black_mod; } else { black_next[i + 1] = (black_next[i + 1] + black_counts[i]) % black_mod; } } black_counts = black_next; } (black_counts.iter().sum::<i64>() % black_mod) as i32 } }